mapper.update:
update auth_codes
set attempt_count = attempt_count +1
where auth_code_id = #{authCodeId}

mapper.select:
select count(*)
from auth_codes
where target_type = #{targetType}
and target_value = #{targetValue}
and purpose = #{purpose}
and created_at >= #{from}

mapper.update:
update auth_codes
set used_at = CONVERT_TZ(NOW(6), '+00:00', '+09:00')
where target_type = #{targetType}
  and target_value = #{targetValue}
  and purpose = #{purpose}
  and verified_at is not null
  and used_at is null
  and verified_at >= date_sub(CONVERT_TZ(NOW(6), '+00:00', '+09:00'), interval 10 minute)
